INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('f3d44cfc78f9fbde', 'CA', '["federal"]', 'candidate_eligibility', 'Is there a U.S. Senate race in California for the 2026 cycle?', '["Are any California U.S. Senate seats up for election in 2026?","When is the next U.S. Senate election in CA?","Is Alex Padilla or Adam Schiff up for re-election in 2026?"]', 'No. There is no regular U.S. Senate election in California in 2026. Senator Alex Padilla (Class 3) is not up until 2028, and Senator Adam Schiff (Class 1) is not up until 2030.', 'https://www.sos.ca.gov/elections/upcoming-elections', 'California Secretary of State – Upcoming Elections', '2026-05-11', 'per_cycle', 'official_source_direct', 'Federal candidates and consultants', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('aab5de6763c3a528', 'CA', '["state"]', 'candidate_eligibility', 'Can Governor Gavin Newsom run for re-election in 2026?', '["Is the California Governor''s seat open in 2026?","What are the term limits for California Governor?","Can Newsom seek a third term?"]', 'No. The Governor''s seat is open in 2026 because Gavin Newsom is term-limited. Under the California Constitution, the Governor is limited to two terms in a lifetime.', 'https://leginfo.legislature.ca.gov/faces/codes_displayText.xhtml?lawCode=CONS&division=&title=&part=&chapter=&article=V', 'California Constitution Article V § 2', '2026-05-11', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('2e551d5802457b4a', 'CA', '["federal","state"]', 'ballot_access', 'How does California''s ''Top-Two'' primary system work for the 2026 election?', '["Does California have a closed primary?","Can Republicans vote for Democrats in the CA primary?","How do candidates advance to the general election in CA?"]', 'All candidates for voter-nominated offices appear on a single ballot regardless of party preference. The top two vote-getters, regardless of party, advance to the general election; even if one candidate receives a majority in the primary, a general election is still held between the top two.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=8002.5.&lawCode=ELEC', 'Cal. Elec. Code § 8002.5', '2026-05-11', 'static', 'statute_citation', 'All federal and state candidates (except Presidential and party central committees)', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('eb28e18e7e34822b', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When is the 2026 California Primary Election?', '["What date is the CA primary in 2026?","California 2026 primary date","When do polls open for the CA primary?"]', 'The California Primary Election is on Tuesday, June 2, 2026. Polls are open from 7:00 a.m. to 8:00 p.m.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=1201.&lawCode=ELEC', 'Cal. Elec. Code § 1201', '2026-05-11', 'per_cycle', 'statute_citation', 'All candidates and voters', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('c1c7a1acab2466e7', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When is the 2026 California General Election?', '["What date is the CA general election in 2026?","CA 2026 midterm election date","When is Election Day 2026 in California?"]', 'The California General Election is on Tuesday, November 3, 2026. All registered voters will receive a mail-in ballot starting 29 days before this date.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=1200.&lawCode=ELEC', 'Cal. Elec. Code § 1200', '2026-05-11', 'per_cycle', 'statute_citation', 'All candidates and voters', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('2010a8cc241f1642', 'CA', '["federal"]', 'redistricting', 'Which congressional maps are in effect for the 2026 election cycle in California?', '["Did California change its congressional districts for 2026?","What is Prop 50''s impact on 2026 house races?","Are we using the 2021 CRC maps for Congress in 2026?"]', 'The mid-decade maps established by Proposition 50 (The Election Rigging Response Act), passed in a special election in November 2025, are in effect for the 2026 congressional elections. These replace the 2021 Citizens Redistricting Commission boundaries for U.S. House seats.', 'https://leginfo.legislature.ca.gov/faces/billNavClient.xhtml?bill_id=202520260ACA8', 'Resolution Chapter 156, Statutes of 2025 (ACA 8)', '2026-05-11', 'volatile', 'statute_citation', 'U.S. House candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('cf87f3a232d1199c', 'CA', '["state"]', 'redistricting', 'Who drew the State Assembly and State Senate maps for the 2026 cycle?', '["Were the legislative maps changed by Prop 50?","Are state legislative districts the same as 2024?","Who has authority over CA legislative redistricting?"]', 'The California Citizens Redistricting Commission (CRC) boundaries drawn in 2021 remain authoritative for State Assembly and State Senate districts in 2026. Proposition 50 only affected congressional maps.', 'https://www.wedrawthelinesca.org/final_maps', 'California Citizens Redistricting Commission', '2026-05-11', 'static', 'official_source_direct', 'State Assembly and State Senate candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('e3306decc2f4dae1', 'CA', '["state"]', 'finance_ethics', 'What are the 2025-2026 contribution limits for a candidate running for Governor?', '["How much can an individual give to a Governor candidate in CA?","What is the max donation for statewide office in 2026?","CA Governor contribution limits 2026"]', 'For the 2025-2026 cycle, individuals and non-small contributor PACs may contribute up to $39,200 per election to a candidate for Governor.', 'https://www.fppc.ca.gov/learn/campaign-rules/state-contribution-limits.html', 'FPPC – State Contribution Limits', '2026-05-11', 'per_cycle', 'official_source_direct', 'Governor candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('0d03e2ded873700e', 'CA', '["state","county","municipal"]', 'finance_ethics', 'What are the individual contribution limits for State Legislative or local candidates in 2026?', '["Max donation for CA State Assembly 2026","CA State Senate contribution limits","City council default contribution limits CA"]', 'For the 2025-2026 cycle, the limit for individuals and PACs is $5,900 per election for State Assembly, State Senate, and local/county candidates (unless a local ordinance supersedes). Other statewide offices (like Attorney General or Treasurer) have a limit of $9,800 per election.', 'https://www.fppc.ca.gov/learn/campaign-rules/state-contribution-limits.html', 'FPPC – State Contribution Limits', '2026-05-11', 'per_cycle', 'official_source_direct', 'Legislative and Local candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('632c2192c7feb110', 'CA', '["state"]', 'finance_ethics', 'Can a corporation contribute directly to a candidate for state office in California?', '["Are corporate contributions legal in CA?","Can my business donate to a state candidate?","California corporate donation rules for state candidates"]', 'Yes. California law permits corporations to make direct contributions to state candidates, subject to the same limits as individuals (e.g., $5,900 for legislative candidates). This does not apply to federal candidates.', 'https://www.fppc.ca.gov/learn/campaign-rules/state-contribution-limits.html', 'FPPC – Campaign Rules for State Candidates', '2026-05-11', 'static', 'official_source_direct', 'State candidates and corporate donors', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('18e2c37ad031abdd', 'CA', '["state"]', 'filing_requirements', 'What is the 2026 filing fee for the office of Governor in California?', '["How much does it cost to run for Governor in CA?","California Governor filing fee amount","Candidate filing fees for statewide office"]', 'The filing fee for Governor is 2% of the annual salary at the time of filing, which for 2026 is approximately $4,682.02. This fee must be paid to the Secretary of State.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=8103.&lawCode=ELEC', 'Cal. Elec. Code § 8103', '2026-05-11', 'per_cycle', 'statute_citation', 'Governor candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('d33b6d27a16127cb', 'CA', '["state"]', 'filing_requirements', 'What is the filing fee for State Assembly or State Senate in 2026?', '["Cost to run for CA State Assembly","State Senate filing fee CA","How much is the legislative filing fee in California?"]', 'The filing fee for the State Legislature is 1% of the annual salary at the time of filing, which for 2026 is approximately $1,282.15.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=8103.&lawCode=ELEC', 'Cal. Elec. Code § 8103', '2026-05-11', 'per_cycle', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('5f6ea2e21af7a7fd', 'CA', '["federal","state"]', 'filing_requirements', 'How can a candidate avoid paying the filing fee in California?', '["Signatures in lieu of filing fee CA","Can I run for office in CA for free?","What is the signature threshold for in-lieu petitions?"]', 'Candidates may submit a ''petition in lieu of filing fee'' to reduce or eliminate the fee by collecting signatures from registered voters. The threshold varies by office (e.g., 10,000 for statewide, 3,000 for Congress).', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=8106.&lawCode=ELEC', 'Cal. Elec. Code § 8106', '2026-05-11', 'static', 'statute_citation', 'All federal and state candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('3613b48f71e52495', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the Form 700 and when must a candidate file it?', '["Statement of Economic Interests CA requirement","When is Form 700 due for candidates?","Do CA candidates have to disclose personal assets?"]', 'Form 700 (Statement of Economic Interests) is a mandatory disclosure of personal financial holdings. Candidates must file it no later than the final filing date for their declaration of candidacy.', 'https://www.fppc.ca.gov/Form700.html', 'FPPC – Form 700 Statement of Economic Interests', '2026-05-11', 'static', 'official_source_direct', 'All candidates and public officials', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('447eb942abb54292', 'CA', '["state","county","municipal"]', 'finance_ethics', 'How soon must a candidate committee file Form 410 after reaching the $2,000 threshold?', '["When to register a campaign committee in CA","Form 410 filing deadline","What is the money threshold to trigger committee registration in CA?"]', 'A committee must file Form 410 within 10 days of receiving $2,000 or more in contributions. During the 90 days before an election, committees must file within 24 hours of reaching the threshold.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=84101.&lawCode=GOV', 'Cal. Gov. Code § 84101', '2026-05-11', 'static', 'statute_citation', 'State and local candidate committees', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('2ebae586bef55ba6', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Does every registered voter in California automatically receive a mail-in ballot in 2026?', '["California universal mail-in voting","Do I have to request an absentee ballot in CA?","Will I get a ballot in the mail automatically?"]', 'Yes. Per AB 37, all registered voters in California are automatically sent a mail-in ballot for every election. Ballots are mailed out starting 29 days before the election.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=3000.5.&lawCode=ELEC', 'Cal. Elec. Code § 3000.5', '2026-05-11', 'static', 'statute_citation', 'All registered voters', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('c48f88b1805841d9', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the deadline to register to vote in California for the 2026 primary?', '["Voter registration deadline CA 2026","When is the last day to register for the June primary?","CA 15-day voter registration rule"]', 'The standard deadline to register to vote is 15 days before the election (May 18, 2026). However, voters can still register ''conditionally'' at any polling place or vote center up through Election Day.', 'https://www.sos.ca.gov/elections/voter-registration', 'California Secretary of State – Voter Registration', '2026-05-11', 'per_cycle', 'official_source_direct', 'All voters', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('018de7408fe3fa1e', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'How does ''Conditional Voter Registration'' work in California?', '["Same-day voter registration CA","Can I register to vote on Election Day in California?","CVR process CA"]', 'Conditional Voter Registration (CVR) allows eligible citizens to register and vote after the 15-day deadline. CVR must be done in person at a county elections office, vote center, or designated satellite location.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=2170.&lawCode=ELEC', 'Cal. Elec. Code § 2170', '2026-05-11', 'static', 'statute_citation', 'Voters who missed the 15-day deadline', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('792c0b0a8b8929ca', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Is a photo ID required to vote at the polls in California?', '["California voter ID laws","Do I need my driver''s license to vote in CA?","Poll ID requirements CA"]', 'Generally, no. Most voters do not need to show ID. First-time voters who registered by mail without providing a driver''s license or SSN may be asked for ID (photo or non-photo) at the polls.', 'https://www.sos.ca.gov/elections/voting-resources/voting-california/what-bring', 'California Secretary of State – Voter ID Guide', '2026-05-11', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('33f6fda273b1c137', 'CA', '["county"]', 'voter_interaction', 'How many California counties have adopted the Voter''s Choice Act (VCA) for 2026?', '["Which counties use vote centers vs polling places?","VCA counties list 2026","Is Los Angeles a Voter''s Choice Act county?"]', 'For the 2026 cycle, 29 of California''s 58 counties are participating in the Voter''s Choice Act, which replaces traditional polling places with regional vote centers. This includes Los Angeles County, the state''s largest voting jurisdiction.', 'https://www.sos.ca.gov/elections/voters-choice-act', 'California Secretary of State – VCA Counties', '2026-05-11', 'volatile', 'official_source_direct', 'Voters in VCA-participating counties', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('da61264ed653ccbd', 'CA', '["state"]', 'candidate_eligibility', 'What are the term limits for members of the California State Legislature?', '["How long can someone serve in the CA Assembly?","Prop 28 term limits","State Senate term limits CA"]', 'Under Proposition 28 (2012), individuals may serve a total of 12 years in the State Legislature during their lifetime. This time can be served in one house or split between the Assembly and Senate.', 'https://leginfo.legislature.ca.gov/faces/codes_displayText.xhtml?lawCode=CONS&division=&title=&part=&chapter=&article=IV', 'California Constitution Article IV § 2(a)(4)', '2026-05-11', 'static', 'statute_citation', 'State Assembly and State Senate candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('f5727e3d177f07ea', 'CA', '["state"]', 'recall_rules', 'What is the signature threshold to qualify a recall against a statewide officer like the Governor?', '["How many signatures to recall a CA Governor?","CA recall percentage requirement","Recalling a statewide official in California"]', 'The threshold is 12% of the last vote for the office. Additionally, signatures must be collected from at least five counties equal to 1% of the last vote for the office in each of those counties.', 'https://leginfo.legislature.ca.gov/faces/codes_displayText.xhtml?lawCode=CONS&division=&title=&part=&chapter=&article=II', 'California Constitution Article II § 14(b)', '2026-05-11', 'static', 'statute_citation', 'Statewide officials', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('3db9f095ba1bbc16', 'CA', '["federal","state"]', 'ballot_access', 'Can a candidate include a ''Statement of Qualifications'' in the voter information guide?', '["CA candidate statement rules","How much does it cost to put a statement in the voter guide?","Candidate statement word limit CA"]', 'Yes. Candidates for state and federal office may submit a 250-word statement. Candidates must typically pay their pro-rata share of the printing costs, unless they meet specific financial hardship criteria.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=13307.&lawCode=ELEC', 'Cal. Elec. Code § 13307', '2026-05-11', 'static', 'statute_citation', 'Voter-nominated and local candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('048c977f65f49d7c', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'candidate_eligibility', 'Can a person with a felony conviction vote in California while on parole or probation?', '["Felon voting rights CA","Prop 17 voting rights","Can you vote while on parole in California?"]', 'Yes. Under Proposition 17 (2020), individuals with felony convictions regain the right to vote immediately upon the completion of their prison term. Being on parole or probation does not restrict a person''s right to register and vote in California.', 'https://www.sos.ca.gov/elections/voting-resources/voting-california/who-can-vote-california/voting-rights-restoration', 'California Secretary of State – Voting Rights Restoration', '2026-05-11', 'static', 'official_source_direct', 'All eligible citizens', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('51d51c3958782b46', 'CA', '["state"]', 'finance_ethics', 'Are contribution limits in California applied per election or per cycle?', '["CA primary vs general donation limits","Can a donor give twice in one year in CA?","FPPC per election rule"]', 'California limits are applied ''per election.'' This means a donor can give the maximum amount for the primary and then give the maximum amount again for the general election, provided the candidate advances.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=85301.&lawCode=GOV', 'Cal. Gov. Code § 85301', '2026-05-11', 'static', 'statute_citation', 'State candidates and donors', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('04ff407dc3bbcc1f', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the standard voter registration deadline for the November 3, 2026 California General Election?', '["When is the last day to register for the 2026 general election?","General election registration deadline CA 2026","How many days before the general election must I register?"]', 'The standard 15-day voter registration deadline for the 2026 General Election is October 19, 2026. However, voters can still utilize Conditional Voter Registration (CVR) up through Election Day.', 'https://www.sos.ca.gov/elections/voter-registration', 'California Secretary of State – Voter Registration', '2026-05-11', 'per_cycle', 'official_source_direct', 'All voters', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('0b532b5117b35be9', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When do mail ballots go out for the 2026 California General Election?', '["When does early voting start for the general election?","When will CA voters receive their general election ballots?","Mail ballot mail-out date 2026"]', 'County elections officials must begin mailing ballots to all active registered voters 29 days before the election, which for the General Election is October 5, 2026. This also marks the first day of early voting at county elections offices.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=3000.5.&lawCode=ELEC', 'Cal. Elec. Code § 3000.5', '2026-05-11', 'per_cycle', 'statute_citation', 'All voters', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('df84e5ae710225e8', 'CA', '["federal","state"]', 'ballot_access', 'How many signatures are required for a Petition in Lieu of Filing Fee for statewide, U.S. House, or State Legislative candidates?', '["In lieu signature threshold Congress CA","How many signatures to waive filing fee for State Assembly?","Signatures needed to avoid paying fee CA"]', 'To fully waive the filing fee, candidates for statewide office must collect 10,000 valid signatures. U.S. House and State Senate candidates must collect 3,000 signatures. State Assembly candidates must collect 1,500 signatures.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=8106.&lawCode=ELEC', 'Cal. Elec. Code § 8106', '2026-05-11', 'static', 'statute_citation', 'Congressional and State Legislative candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('02934eb7c9a88e89', 'CA', '["state"]', 'ballot_access', 'How many valid signatures are required to qualify a state ballot initiative for the 2026 cycle?', '["CA citizen initiative signature requirement 2026","How many signatures to get a proposition on the ballot?","Signature threshold for constitutional amendments CA"]', 'For the 2026 cycle, qualifying a statutory initiative requires 545,651 valid signatures (exactly 5% of the 10,933,016 votes cast for Governor in 2022). A constitutional amendment initiative requires 874,641 valid signatures (8% of that turnout).', 'https://www.sos.ca.gov/elections/ballot-measures/how-qualify-initiative', 'California Secretary of State – Initiative Qualification', '2026-05-11', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('0ae30d676c1c5aad', 'CA', '["state"]', 'ballot_access', 'What is the signature requirement to qualify a new political party in California for 2026?', '["How to form a new political party CA","Signatures needed for third party ballot access","Party qualification threshold California"]', 'To qualify a new party, organizers must collect valid petition signatures equal to 10% of the votes cast at the last gubernatorial election. Alternatively, a party can qualify if exactly 0.33% of total registered state voters explicitly register with that party preference.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=5100.&lawCode=ELEC', 'Cal. Elec. Code § 5100', '2026-05-11', 'static', 'statute_citation', 'Third-party organizers', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('e7a5bdb610958a3f', 'CA', '["federal","state","county","municipal"]', 'finance_ethics', 'When must a committee file Form 462 to report Independent Expenditures?', '["Independent expenditure reporting timeline CA","When is Form 462 due?","FPPC rules for reporting independent spending"]', 'A committee making an independent expenditure must file Form 462 with the FPPC via email within 10 days of making the expenditure. This verifies that the expenditure was not coordinated with the candidate or opposing committee.', 'https://www.fppc.ca.gov/learn/campaign-rules/where-and-when-to-file-campaign-statements.html', 'FPPC – Campaign Filing Schedules', '2026-05-11', 'static', 'official_source_direct', 'Independent Expenditure Committees', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('4060316cc34d02cc', 'CA', '["state","county","municipal"]', 'finance_ethics', 'What triggers the requirement to file as a ''Major Donor'' under Form 461 in California?', '["Major Donor reporting threshold CA","When do individuals have to file Form 461?","How much can I donate before becoming a Major Donor?"]', 'An individual or entity becomes a ''Major Donor'' and must file Form 461 if they make contributions totaling $10,000 or more in a single calendar year to California state or local candidates and committees.', 'https://www.fppc.ca.gov/learn/campaign-rules/major-donor-and-independent-expenditure-committees.html', 'FPPC – Major Donor Committees', '2026-05-11', 'static', 'official_source_direct', 'Donors and entities', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('e69bbde01479b70b', 'CA', '["state","county","municipal"]', 'finance_ethics', 'What is the filing schedule for the Form 460 Recipient Committee Campaign Statement?', '["When are campaign finance reports due in CA?","Form 460 deadlines 2026","How often do I file my campaign finance report?"]', 'Committees must file semi-annual reports (typically due Jan 31 and July 31). Additionally, during an election year, they must file pre-election statements (generally 40 days and 12 days before the election) detailing all receipts and expenditures.', 'https://www.fppc.ca.gov/learn/campaign-rules/where-and-when-to-file-campaign-statements.html', 'FPPC – Campaign Filing Schedules', '2026-05-11', 'static', 'official_source_direct', 'Candidate and Recipient Committees', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('08e33b6b937ae2b3', 'CA', '["state","county","municipal"]', 'finance_ethics', 'What is the definition of the 90-day window for Late Contributions in California?', '["Form 497 late contribution timeline","When do I have to report donations within 24 hours?","CA 90-day election window reporting"]', 'Under Gov. Code § 82036, a ''Late Contribution'' is any contribution of $1,000 or more made or received during the entire 90-day period immediately preceding an election. These must be reported within 24 hours using Form 497.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=82036.&lawCode=GOV', 'Cal. Gov. Code § 82036', '2026-05-11', 'static', 'statute_citation', 'Candidate and Recipient Committees', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('71adac7eae02815c', 'CA', '["state","federal"]', 'candidate_eligibility', 'What are the specific residency and age requirements to run for Governor or U.S. House in California?', '["How old to run for Governor in CA?","Do I have to live in the district to run for Congress in CA?","CA candidate age and residency rules"]', 'A candidate for Governor must be an ''elector'' (at least 18 years old) and a resident of California for 5 years immediately preceding the election. A U.S. House candidate must be at least 25 years old, a citizen for 7 years, and an inhabitant of California when elected.', 'https://leginfo.legislature.ca.gov/faces/codes_displayText.xhtml?lawCode=CONS&division=&title=&part=&chapter=&article=V', 'California Constitution Article V § 2', '2026-05-11', 'static', 'statute_citation', 'Federal and Statewide candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('b93116e7d63465e4', 'CA', '["federal","state","county","municipal","special_district"]', 'ballot_access', 'What are the rules for a candidate''s Ballot Designation in California?', '["3-word descriptor on ballot CA","What can I put under my name on the ballot?","Ballot designation rules California"]', 'A ballot designation appears under the candidate''s name and is limited to three words (with some exceptions for incumbents). It must accurately describe the candidate''s current principal profession, vocation, or occupation, or state their incumbent status, and must not mislead voters.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=13107.&lawCode=ELEC', 'Cal. Elec. Code § 13107', '2026-05-11', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('bc1db3c34472c5d3', 'CA', '["federal","state"]', 'ballot_access', 'How does the ''Sore Loser'' law apply under California''s Top-Two Primary system?', '["Can a candidate who lost the primary run as an independent in the general?","Write-in campaign after losing CA primary","Sore loser rule Top-Two CA"]', 'Under the Top-Two Primary system, a candidate who fails to finish in the top two in the primary election cannot run as an independent or write-in candidate in the general election for that same voter-nominated office.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=8605.&lawCode=ELEC', 'Cal. Elec. Code § 8605', '2026-05-11', 'static', 'statute_citation', 'Voter-nominated office candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('9ee9bdc7f1a67fda', 'CA', '["county","municipal","special_district"]', 'recall_rules', 'What is the signature threshold to recall a local official like a city councilmember or county supervisor?', '["Local recall threshold CA","Signatures needed to recall a mayor in California","School board recall signature requirements"]', 'For local officials, the threshold is a percentage of the total registered voters in the jurisdiction, sliding from 10% for large districts (over 100,000 voters) up to 30% for very small districts (under 1,000 voters). For most medium-sized jurisdictions, it is 20%.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=11221.&lawCode=ELEC', 'Cal. Elec. Code § 11221', '2026-05-11', 'static', 'statute_citation', 'Local officials and recall committees', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('e038aca7504fdca8', 'CA', '["county","municipal","special_district"]', 'recall_rules', 'What is the procedure for initiating a local recall in California?', '["Steps to recall a local politician CA","Notice of Intent to Recall process","How do you start a recall election for a school board?"]', 'Proponents must serve a ''Notice of Intention to Circulate Recall Petition'' on the official, publish it, and file it with the local elections official. Once the petition format is approved, proponents have a set window (e.g., 40 to 160 days, depending on jurisdiction size) to collect signatures.', 'https://leginfo.legislature.ca.gov/faces/codes_displayText.xhtml?lawCode=ELEC&division=11.&title=&part=&chapter=1.&article=2.', 'Cal. Elec. Code § 11020 et seq.', '2026-05-11', 'static', 'statute_citation', 'Local officials and recall committees', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('a5cb3b1e18dc01f5', 'CA', '["judicial"]', 'election_dates', 'How are judges selected and retained for the California Supreme Court and Courts of Appeal?', '["Do we elect Supreme Court judges in California?","Appellate court judicial elections CA","California judicial retention elections"]', 'Supreme Court and Appellate Court justices are appointed by the Governor and confirmed by the Commission on Judicial Appointments. They do not run in contested elections; instead, voters decide whether to keep them in ''yes or no'' retention elections at the end of their 12-year terms.', 'https://leginfo.legislature.ca.gov/faces/codes_displayText.xhtml?lawCode=CONS&division=&title=&part=&chapter=&article=VI', 'California Constitution Article VI § 16(a)', '2026-05-11', 'static', 'statute_citation', 'Appellate and Supreme Court Justices', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('bac4bf4f924bce45', 'CA', '["judicial"]', 'election_dates', 'How are Trial Court (Superior Court) judges elected in California?', '["Superior court judge elections CA","Are trial judges partisan in California?","Running for judge in CA"]', 'Superior Court judges are elected in countywide, nonpartisan elections for 6-year terms. If an incumbent is unopposed, their name typically does not appear on the ballot, and they are declared re-elected unless a write-in petition is filed.', 'https://leginfo.legislature.ca.gov/faces/codes_displayText.xhtml?lawCode=CONS&division=&title=&part=&chapter=&article=VI', 'California Constitution Article VI § 16(b)', '2026-05-11', 'static', 'statute_citation', 'Trial Court Judges', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('4a6b73a7925b08d9', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What are the state restrictions on placing campaign signs near highways?', '["Caltrans campaign sign rules","Where can I place political yard signs in CA?","State Outdoor Advertising Act political signs"]', 'The State Outdoor Advertising Act forbids placing campaign signs on public rights-of-way, including state highways, fences, trees, or utility poles. Signs must be on private property with the owner''s permission and must be removed within 10 days after the election.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=5405.3.&lawCode=BPC', 'Cal. Bus. & Prof. Code § 5405.3', '2026-05-11', 'static', 'statute_citation', 'All campaigns', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('aab1527a2f9f6c30', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What are the disclosure requirements for campaign text messages (SMS) and robocalls in California?', '["AB 1494 text message rules","Do campaign texts need an ''Ad paid for by'' disclaimer?","Robocall disclosure requirements CA"]', 'Under AB 1494 and FPPC rules, mass text messages and robocalls must include an ''Ad paid for by'' or ''Who funded this ad?'' disclosure. For texts, this can be a direct statement or a link to a website containing the full disclosure.', 'https://www.fppc.ca.gov/siteassets/documents/tad/fact_sheets/political_ads/political_ad_disclosures_fact_sheet_final.pdf', 'FPPC – Political Advertisement Disclosures', '2026-05-11', 'static', 'official_source_direct', 'All campaigns using digital communication', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('eb0beded58e1d3e2', 'CA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can a candidate use campaign funds for personal expenses?', '["Personal use of campaign funds CA","Can I buy a car with campaign money?","California rules on spending campaign donations"]', 'No. The California Government Code strictly prohibits the personal use of campaign funds. Expenditures must be directly related to a political, legislative, or governmental purpose. If the expense confers a substantial personal benefit, it must be directly related to a campaign activity.', 'https://leginfo.legislature.ca.gov/faces/codes_displayText.xhtml?lawCode=GOV&division=9.&title=9.&part=&chapter=9.&article=4.', 'Cal. Gov. Code § 89510 et seq.', '2026-05-11', 'static', 'statute_citation', 'All state and local candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('9c9437e19d67aa41', 'CA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How long must a candidate committee retain its campaign finance records?', '["Campaign record retention requirements CA","How many years to keep campaign receipts?","FPPC audit record retention"]', 'Candidate committees, major donors, and independent expenditure committees must retain all detailed accounts, records, bills, and receipts for four years following the date the campaign statement to which they relate is filed.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=84104.&lawCode=GOV', 'Cal. Gov. Code § 84104', '2026-05-11', 'static', 'statute_citation', 'Campaign Treasurers and Candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('cf4ef6e5ef6462e5', 'CA', '["state","county","municipal"]', 'finance_ethics', 'Are there independent local ethics commissions in major California cities?', '["LA Ethics Commission rules","Does San Francisco have its own campaign finance board?","Local election commission equivalents in CA"]', 'Yes. Major municipalities have their own independent ethics agencies, such as the Los Angeles City Ethics Commission and the San Francisco Ethics Commission, which enforce local campaign finance ordinances that often impose stricter contribution limits and reporting requirements than state law.', 'https://ethics.lacity.org/', 'Los Angeles City Ethics Commission', '2026-05-11', 'static', 'secondary_source', 'Candidates in specific major cities', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('28bb7b25eb251430', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Where can a voter complete Conditional Voter Registration (CVR) in California?', '["Where to do same-day registration CA","Can I register at a polling place on Election Day?","CVR location requirements"]', 'Voters can complete CVR (same-day registration) at their county elections office, any official vote center, or designated satellite locations from the close of regular registration (15 days prior) up through 8:00 p.m. on Election Day.', 'https://www.sos.ca.gov/elections/voter-registration/same-day-reg', 'California Secretary of State – Same Day Registration', '2026-05-11', 'static', 'official_source_direct', 'Voters and Get-Out-The-Vote operations', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('0515e8fd4d6ff318', 'CA', '["county","municipal"]', 'voter_interaction', 'What are the rules for official ballot drop boxes in California counties?', '["Are ballot drop boxes secure in CA?","When do drop boxes open?","County requirements for mail ballot boxes"]', 'Counties must provide secure, accessible drop boxes available starting 28 days before the election. Drop boxes must be locked exactly at 8:00 p.m. on Election Day. State law mandates strict chain-of-custody and security protocols for ballot retrieval.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=3025.&lawCode=ELEC', 'Cal. Elec. Code § 3025', '2026-05-11', 'static', 'statute_citation', 'Voters and county administrators', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('805c8a88413586fa', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Under what circumstances is a provisional ballot used at a California polling place?', '["When do I have to cast a provisional ballot?","Are provisional ballots counted in CA?","Voting if my name isn''t on the roster"]', 'Provisional ballots are used if a voter''s eligibility cannot immediately be verified (e.g., name not on roster, registered in another county, or marked as already having returned a mail ballot). They are counted after elections officials verify the voter''s registration and confirm they haven''t voted elsewhere.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=14310.&lawCode=ELEC', 'Cal. Elec. Code § 14310', '2026-05-11', 'static', 'statute_citation', 'Voters', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('94ad34f88283c216', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the deadline for a mail-in ballot to be received and counted in California?', '["Does my ballot have to arrive by Election Day in CA?","California mail ballot postmark rule","7-day receipt deadline for ballots"]', 'A mail-in ballot will be counted if it is postmarked on or before Election Day and received by the county elections official no later than 7 days after Election Day.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=3020.&lawCode=ELEC', 'Cal. Elec. Code § 3020', '2026-05-11', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-11T17-25-38_california_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('5af4d6a4655456c2', 'CA', '["state","county"]', 'finance_ethics', 'What are the penalties for filing campaign finance reports late with the FPPC?', '["How much is the fine for late campaign reports in CA?","FPPC late filing fees","What happens if I miss the Form 460 deadline?"]', 'Late statements are subject to a standard fine of $10 per day from the filing officer. Additionally, failure to file can result in a direct FPPC enforcement penalty of up to $5,000 per violation.', 'https://www.fppc.ca.gov/learn/campaign-rules/where-and-when-to-file-campaign-statements.html', 'Cal. Gov. Code § 91013', '2026-05-11', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('99aa91f9051cf644', 'CA', '["state","county","municipal"]', 'finance_ethics', 'Are foreign nationals prohibited from contributing to state and local campaigns in California?', '["Can a foreign citizen donate to my city council race?","Foreign contribution ban CA","Are non-citizens allowed to give to California campaigns?"]', 'Yes. California law (Gov. Code § 85320) specifically mirrors federal law by prohibiting a foreign principal or foreign national from making any contribution or independent expenditure in connection with any state or local election.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=85320.&lawCode=GOV', 'Cal. Gov. Code § 85320', '2026-05-11', 'static', 'statute_citation', 'All state and local campaigns', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('ec0c4a9531564dbf', 'CA', '["state","county"]', 'finance_ethics', 'How are contribution limits aggregated between affiliated entities in California?', '["Can two PACs run by the same person double the limit?","Affiliated committee aggregation CA","Do corporate subsidiaries share a contribution limit?"]', 'Contributions made by affiliated entities (e.g., a parent corporation and its subsidiaries, or two PACs controlled by the same individuals) are aggregated and treated as a single contribution for the purpose of enforcing contribution limits.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=85311.&lawCode=GOV', 'Cal. Gov. Code § 85311', '2026-05-11', 'static', 'statute_citation', 'Donors and Campaign Treasurers', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('469ce6611936584b', 'CA', '["county","municipal"]', 'candidate_eligibility', 'How are candidate qualifications verified or challenged locally?', '["Who checks if a candidate meets the requirements?","How to challenge a candidate''s diploma in CA","Elec Code 13.5 verification"]', 'Under Elections Code § 13.5, candidates for certain offices must file documentation (degrees, diplomas) proving their qualifications. However, the elections official is not required to verify the authenticity of the documents; challenges must generally be pursued through the courts via a writ of mandate.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=13.5.&lawCode=ELEC', 'Cal. Elec. Code § 13.5', '2026-05-11', 'static', 'statute_citation', 'Local candidates and opponents', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('f95952add9a08edc', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'How is the order of candidates'' names on the ballot determined in California?', '["Who gets listed first on the ballot in CA?","Is ballot order alphabetical?","Randomized alphabet drawing CA"]', 'Ballot order is determined by a ''Randomized Alphabet Drawing'' conducted by the Secretary of State 82 days before the election. Furthermore, for statewide and U.S. House races, candidate names are rotated throughout the Assembly districts to prevent positional bias.', 'https://www.sos.ca.gov/elections/randomized-alphabet', 'California Secretary of State – Randomized Alphabet', '2026-05-11', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('220976799560973d', 'CA', '["federal","state"]', 'candidate_eligibility', 'Can a candidate run for more than one office on the same ballot in California?', '["Running for two offices at once CA","Can I run for Assembly and Congress at the same time?","Multiple office ballot access"]', 'No. Under Elections Code § 8003(b), no person may file nomination papers for more than one office at the same election, with limited exceptions for certain party central committee positions or non-incompatible local board seats.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=8003.&lawCode=ELEC', 'Cal. Elec. Code § 8003', '2026-05-11', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('ae22325c2886eabe', 'CA', '["state"]', 'election_dates', 'How are vacancies in the California State Legislature filled?', '["Special election for State Assembly CA","How is a vacant state senate seat filled?","Legislative vacancy procedures"]', 'Legislative vacancies are filled by special election. The Governor must call the special election within 14 days of the vacancy occurring. The election is generally held on a Tuesday at least 126 days, but not more than 140 days, after the proclamation.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=1773.&lawCode=GOV', 'Cal. Gov. Code § 1773', '2026-05-11', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('71b7412b64959c50', 'CA', '["state","county","municipal"]', 'finance_ethics', 'How does a candidate formally close or terminate their campaign committee?', '["Terminating a campaign committee CA","How to close Form 410","FPPC account closure rules"]', 'To terminate a committee, the candidate must spend down all funds (leaving a $0 balance), ensure all debts are paid or forgiven, and file a terminating Form 410 along with a final Form 460 reporting the zero balance.', 'https://www.fppc.ca.gov/learn/campaign-rules/where-and-when-to-file-campaign-statements.html', 'FPPC – Campaign Rules', '2026-05-11', 'static', 'official_source_direct', 'Campaign Treasurers', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('8bef81e19674d09a', 'CA', '["state","county","municipal"]', 'finance_ethics', 'What must a candidate do with leftover or surplus campaign funds?', '["Surplus funds disposition CA","Can I give my leftover campaign money to charity?","Gov Code 89519 rules"]', 'Under Gov. Code § 89519, funds become ''surplus'' 90 days after leaving office or 90 days after the post-election reporting period. Surplus funds can only be used for paying outstanding debts, refunding contributors, charitable donations, or contributions to political parties (with restrictions).', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=89519.&lawCode=GOV', 'Cal. Gov. Code § 89519', '2026-05-11', 'static', 'statute_citation', 'Candidates leaving office or concluding campaigns', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('ac5a88d4be6f42e3', 'CA', '["state"]', 'finance_ethics', 'What is Cal-ACCESS and who must use it?', '["California electronic filing system","Where do I file my FPPC forms online?","Cal-ACCESS requirement"]', 'Cal-ACCESS is the Secretary of State''s online filing system. State candidates, major donors, and PACs must file their campaign finance disclosure reports electronically through Cal-ACCESS if they receive contributions or make expenditures totaling $25,000 or more.', 'https://www.sos.ca.gov/campaign-lobbying/cal-access-resources', 'California Secretary of State – Cal-ACCESS', '2026-05-11', 'static', 'official_source_direct', 'State-level committees and Major Donors', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('a92d25f4d69a67e7', 'CA', '["federal","state"]', 'runoff_rules', 'What happens in a Top-Two general election if one of the two advancing candidates dies before the election?', '["Deceased candidate Top-Two CA","If a primary winner dies, does the third place person advance?","Replacement candidates Top-Two general"]', 'If a candidate who advanced to the general election dies, their name remains on the ballot (or is removed depending on timing, but no replacement is made). The third-place finisher from the primary does NOT automatically advance to replace them.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=8809.&lawCode=ELEC', 'Cal. Elec. Code § 8809', '2026-05-11', 'static', 'statute_citation', 'Voter-nominated candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('5310ca8d709c7415', 'CA', '["state"]', 'recall_rules', 'How long do proponents have to circulate a recall petition for a statewide officer in California?', '["Recall circulation timeline CA","How many days to get recall signatures?","Statewide recall window"]', 'For statewide officers (like the Governor), proponents have 160 days from the time the petition is approved for circulation by the Secretary of State to collect the necessary number of signatures.', 'https://leginfo.legislature.ca.gov/faces/codes_displayText.xhtml?lawCode=CONS&division=&title=&part=&chapter=&article=II', 'California Constitution Article II § 14(a)', '2026-05-11', 'static', 'statute_citation', 'Recall proponents and Statewide officers', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('237b92df2a34eaf2', 'CA', '["state","county"]', 'finance_ethics', 'Are candidates running for the CalPERS Board of Administration subject to the same campaign finance rules as political candidates?', '["CalPERS board election rules","Do retirement board candidates file Form 460?","PRA application to CalPERS"]', 'Yes. Candidates running for the Board of Administration of the Public Employees'' Retirement System (CalPERS) are explicitly subject to the campaign finance disclosure requirements (like filing Form 460) of the Political Reform Act.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=82036.&lawCode=GOV', 'Cal. Gov. Code § 82036', '2026-05-11', 'static', 'statute_citation', 'CalPERS Board Candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('e1fa8f848435a07e', 'CA', '["federal","state"]', 'ballot_access', 'Are write-in candidates allowed in the November General Election under California''s Top-Two system?', '["Can I run as a write-in for the general election?","Top-Two write in rules CA","General election write in candidates"]', 'No. For voter-nominated offices (like Congress and State Legislature), write-in candidates are only permitted in the Primary Election. Write-in candidates are prohibited on the General Election ballot for these offices.', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=8600.&lawCode=ELEC', 'Cal. Elec. Code § 8600', '2026-05-11', 'static', 'statute_citation', 'Voter-nominated candidates', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('c44cd4aa621f314c', 'CA', '["municipal","county"]', 'finance_ethics', 'Can a city or county impose stricter contribution limits than the state default of $5,900?', '["Local vs state contribution limits CA","Can my city lower the max donation?","Municipal campaign finance ordinances"]', 'Yes. While the state imposes a default limit (currently $5,900) on local jurisdictions under AB 571, cities and counties retain the authority to pass their own local ordinances establishing stricter, lower contribution limits for their municipal races.', 'https://www.fppc.ca.gov/learn/campaign-rules/state-contribution-limits.html', 'FPPC – State and Local Contribution Limits', '2026-05-11', 'static', 'official_source_direct', 'Local candidates and city councils', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('36b54d960dd602a4', 'CA', '["state","county","municipal"]', 'finance_ethics', 'What is a ''Sponsored Committee'' in California?', '["Sponsored PAC rules CA","Committee naming requirements FPPC","Does a union have to put its name on its PAC?"]', 'A ''Sponsored Committee'' is a PAC that is financially supported or managed by a specific organization (like a union, trade association, or corporation). The committee must include the name of its sponsor in the official committee name.', 'https://www.fppc.ca.gov/learn/campaign-rules/where-and-when-to-file-campaign-statements.html', 'FPPC – Campaign Rules', '2026-05-11', 'static', 'official_source_direct', 'PACs and Sponsoring Organizations', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('775e4f5577f35589', 'CA', '["state","county","municipal"]', 'finance_ethics', 'What is a Slate Mailer Organization and what form must they file?', '["Slate mailer reporting CA","Form 400 filing","How are voter guides regulated in California?"]', 'A Slate Mailer Organization is an entity that receives $500 or more to produce a mass mailing that supports or opposes four or more candidates or measures. They must register using Form 400 and report their financial activity.', 'https://www.fppc.ca.gov/learn/campaign-rules/slate-mailer-organizations.html', 'FPPC – Slate Mailer Organizations', '2026-05-11', 'static', 'official_source_direct', 'Consultants and Mail Vendors', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('93c2d51f100efb61', 'CA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What are the physical formatting rules for ''Paid for by'' disclosures on print advertisements?', '["How big does the disclaimer have to be on a mailer?","Prop 34 print ad rules","Disclaimer font size requirements CA"]', 'For print advertisements like mailers and flyers, the ''Ad paid for by'' disclosure must be printed in at least 10-point font, in a color that contrasts with the background, and be clearly legible to the average reader.', 'https://www.fppc.ca.gov/siteassets/documents/tad/fact_sheets/political_ads/political_ad_disclosures_fact_sheet_final.pdf', 'FPPC – Political Advertisement Disclosures', '2026-05-11', 'static', 'official_source_direct', 'All Campaigns and Printers', 'batch_2026-05-11T17-25-38_california_full_v1'),
  ('37796a32595aa362', 'CA', '["state","county","municipal"]', 'finance_ethics', 'What is a ''General Purpose Committee'' under California law?', '["Independent PAC definition CA","What is a general purpose committee?","State PAC vs candidate committee"]', 'A General Purpose Committee is a PAC that is formed to support or oppose multiple candidates or measures across various elections, rather than being primarily formed to support a single specific candidate or single specific ballot measure.', 'https://www.fppc.ca.gov/learn/campaign-rules/general-purpose-committees.html', 'FPPC – General Purpose Committees', '2026-05-11', 'static', 'official_source_direct', 'Political Action Committees', 'batch_2026-05-11T17-25-38_california_full_v1')
